import { ApiProperty } from "@nestjs/swagger";
import { IsEnum } from "class-validator";

import { StringField } from "../../../decorators/field.decorators.ts";

export enum IdType {
  CID = "CID",
}

export class ClientInquiryDto {
  @ApiProperty({ enum: IdType, description: "Type of ID", example: "CID" })
  @IsEnum(IdType)
  id_type!: IdType;

  @ApiProperty({
    description: "ID number (CID)",
    example: "10605001681",
    minLength: 11,
    maxLength: 11,
  })
  @StringField({ minLength: 11, maxLength: 11 })
  id_number!: string;
}
